/**
 * Dashboard.jsx
 * ─────────────────────────────────────────────────────────────
 * Vista principal del dashboard financiero.
 * Muestra: tarjetas de resumen, gráfica de dona, gráfica de
 * barras por mes y las últimas 5 transacciones.
 */

import { useTransactions }        from '../hooks/useTransactions'
import { formatCurrency, formatDateShort } from '../utils/formatCurrency'
import StatCard                   from '../components/common/StatCard'
import DonutChart                 from '../components/common/Chart/DonutChart'
import BarChart                   from '../components/common/Chart/BarChart'
import styles                     from './Dashboard.module.css'

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠',
  salud: '💊', entretenimiento: '🎬', educación: '📚',
  ropa: '👕', otros: '📦',
}

export default function Dashboard() {
  const { transactions, summary, loading, error } = useTransactions()

  if (error) {
    return (
      <div className="feedback feedback-error mt-4">
        ⚠️ {error}
      </div>
    )
  }

  const {
    totalIncome  = 0,
    totalExpense = 0,
    balance      = 0,
    byCategory   = {},
  } = summary || {}

  // Porcentaje del balance sobre los ingresos
  const savingsRate = totalIncome > 0
    ? Math.round((balance / totalIncome) * 100)
    : null

  const recent = transactions.slice(0, 5)

  return (
    <div className={styles.page}>
      {/* ── Encabezado ─────────────────────────────── */}
      <div className={`${styles.pageHeader} animate-fade-up`}>
        <div>
          <h1 className={styles.pageTitle}>Dashboard</h1>
          <p className={styles.pageSubtitle}>
            Resumen de tu actividad financiera
          </p>
        </div>
        <span className={styles.dateLabel}>
          {new Date().toLocaleDateString('es-CO', {
            weekday: 'long', day: 'numeric', month: 'long',
          })}
        </span>
      </div>

      {/* ── Tarjetas de estadísticas ────────────────── */}
      <div className={`grid-4 mb-6`}>
        <StatCard
          label="Balance total"
          value={formatCurrency(balance)}
          subtext="Ingresos − Gastos"
          variant={balance >= 0 ? 'success' : 'danger'}
          icon="⚖️"
          delay={1}
          loading={loading}
        />
        <StatCard
          label="Ingresos"
          value={formatCurrency(totalIncome)}
          subtext="Total registrado"
          variant="success"
          icon="↑"
          delay={2}
          loading={loading}
        />
        <StatCard
          label="Gastos"
          value={formatCurrency(totalExpense)}
          subtext="Total registrado"
          variant="danger"
          icon="↓"
          delay={3}
          loading={loading}
        />
        <StatCard
          label="Tasa de ahorro"
          value={savingsRate !== null ? `${savingsRate}%` : '—'}
          subtext="Del total de ingresos"
          variant={savingsRate >= 20 ? 'success' : 'accent'}
          icon="💾"
          delay={4}
          loading={loading}
        />
      </div>

      {/* ── Gráficas ────────────────────────────────── */}
      <div className={`grid-2 mb-6`}>
        {/* Dona de gastos por categoría */}
        <div className={`card animate-fade-up delay-3`}>
          <div className="card-header">
            <span className="label">Gastos por categoría</span>
          </div>
          <DonutChart data={byCategory} />
        </div>

        {/* Barras de ingresos vs gastos por mes */}
        <div className={`card animate-fade-up delay-4`}>
          <div className="card-header">
            <span className="label">Ingresos vs Gastos — últimos 6 meses</span>
          </div>
          <BarChart transactions={transactions} />
        </div>
      </div>

      {/* ── Últimas transacciones ───────────────────── */}
      <div className={`card animate-fade-up delay-5`}>
        <div className="card-header">
          <span className="label">Últimas transacciones</span>
          <a href="/transactions" className={styles.seeAll}>Ver todas →</a>
        </div>

        {loading ? (
          <div className={styles.skeletonList}>
            {[1,2,3].map((i) => (
              <div key={i} className={styles.skeletonRow}>
                <div className={`skeleton ${styles.skEl1}`} />
                <div className={`skeleton ${styles.skEl2}`} />
                <div className={`skeleton ${styles.skEl3}`} />
              </div>
            ))}
          </div>
        ) : recent.length === 0 ? (
          <p className={styles.emptyMsg}>
            Sin transacciones aún. <a href="/transactions">Agrega la primera →</a>
          </p>
        ) : (
          <ul className={styles.txList}>
            {recent.map((t, i) => (
              <li
                key={t.id}
                className={`${styles.txItem} animate-fade-up delay-${i + 1}`}
              >
                <div className={styles.txLeft}>
                  <span className={styles.txEmoji}>
                    {CATEGORY_EMOJI[t.category] || '📦'}
                  </span>
                  <div>
                    <p className={styles.txDesc}>{t.description}</p>
                    <p className={styles.txMeta}>
                      <span className={`badge ${t.type === 'income' ? 'badge-success' : 'badge-danger'}`}>
                        {t.type === 'income' ? 'Ingreso' : 'Gasto'}
                      </span>
                      <span>{t.category}</span>
                      <span>{formatDateShort(t.date)}</span>
                    </p>
                  </div>
                </div>
                <span className={t.type === 'income' ? styles.amtPos : styles.amtNeg}>
                  {t.type === 'income' ? '+' : '−'}{formatCurrency(t.amount)}
                </span>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  )
}
